import React from 'react';
import './App.css';
import './index.css';

function App() {
  const [count, setCount] = React.useState(0);

  const onClickMinus = () => {
    if(count !== 0) {
      setCount(count - 1);
    }
  };

  const onClickPlus = () => {
    setCount(count + 1);
  };

  const [open, setOpen] = React.useState(true);



  return (
    <div className="App">
       <div className="counter">
             <h2 className="title">Счётчик:</h2>
             <h1 className="output">{count}</h1>
             <div className="block_buttons">
                <button onClick={onClickMinus} className="button Minus">- Minus</button>
                <button onClick={onClickPlus} className="button Plus">Plus +</button>
             </div>
       </div>

       <hr/>

       <div className="modalWindow">
             <button className="open-modal-btn">🔐 Открыть окно</button>
             {
               open && (
                 <img className="img-1" src='http://www.rosphoto.com/images/u/articles/1510/3_13.jpg' alt="Uchiha"/>
               )
             }
       </div>
    </div>
  );
}

export default App;
